import React from "react";

const IntroSection = () => {
  return (
    <section style={{ display: "flex", alignItems: "center", gap: "2rem", maxWidth: "900px", margin: "0 auto 4rem" }}>
      <div style={{ flex: 1 }}>
        <h1 style={{ fontSize: "2.5rem", fontWeight: "900", marginBottom: "1rem" }}>
          Nice to meet you
        </h1>
        <p style={{ fontSize: "1.1rem", lineHeight: "1.6" }}>
          We're John and Jai, co-founders of Hydrant. Our journey started when both us (John, a scientist,
          and Jai, a finance consultant) were trying to solve the same problem on opposite sides of the US.
          After a friend connected us, the rest is history.
        </p>
      </div>
    </section>
  );
};

export default IntroSection;
